/**
 * Generated by `createservice miniapp.SendDTMFToB2CAppService --type mutations`
 */
const { GQLError, GQLErrorCode: { BAD_USER_INPUT, FORBIDDEN, INTERNAL_ERROR } } = require('@open-condo/keystone/errors')
const { fetch } = require('@open-condo/keystone/fetch')
const { getLogger } = require('@open-condo/keystone/logging')
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema } = require('@open-condo/keystone/schema')

const { WRONG_FORMAT, DV_VERSION_MISMATCH } = require('@condo/domains/common/constants/errors')
const { encryptionManager } = require('@condo/domains/common/utils/encryption')
const access = require('@condo/domains/miniapp/access/SendDTMFToB2CAppService')
const { COMMON_VOIP_ERRORS } = require('@condo/domains/miniapp/utils/sendVoIPCallMessage')
const { B2CApp } = require('@condo/domains/miniapp/utils/serverSchema')
const { getCallStatus, CALL_STATUS_ENDED, isCallStatusTokenEqual, parseCallStatusJWTToken, isCallIdValid } = require('@condo/domains/miniapp/utils/voip')
const { RedisGuard } = require('@condo/domains/user/utils/serverSchema/guards')

const logger = getLogger()
const redisGuard = new RedisGuard()

const SEND_DTMF_TO_B2C_APP_LIMIT_BY_CALL_WINDOW_DURATION_IN_SECONDS = 60 // 1 minute
const SEND_DTMF_TO_B2C_APP_LIMIT_BY_CALL_MAX_REQUESTS_PER_WINDOW = 60 // 1 per second basically. Most likely at most user will press the button few times in first 10 seconds and forget, so it should be more than enough for intended use.
const SEND_DTMF_TO_B2C_APP_LIMIT_BY_USER_WINDOW_DURATION_IN_SECONDS = 60 // 1 minute
const SEND_DTMF_TO_B2C_APP_LIMIT_BY_USER_MAX_REQUESTS_PER_WINDOW = SEND_DTMF_TO_B2C_APP_LIMIT_BY_CALL_MAX_REQUESTS_PER_WINDOW * 5 * 3 // 5 people in unit and 3 intercoms 


const SERVICE_NAME = 'sendDTMFToB2CApp'
const ERRORS = {
    DV_VERSION_MISMATCH: {
        mutation: SERVICE_NAME,
        variable: ['data', 'dv'],
        code: BAD_USER_INPUT,
        type: DV_VERSION_MISMATCH,
        message: 'Wrong value for data version number',
    },
    WRONG_SENDER_FORMAT: {
        mutation: SERVICE_NAME,
        variable: ['data', 'sender'],
        code: BAD_USER_INPUT,
        type: WRONG_FORMAT,
        message: 'Invalid format of "sender" field value. {details}',
        correctExample: '{ "dv": 1, "fingerprint": "uniq-device-or-container-id" }',
        messageInterpolation: { details: 'Please, check the example for details' },
    },
    INVALID_CALL_ID: {
        ...COMMON_VOIP_ERRORS.INVALID_CALL_ID,
        mutation: SERVICE_NAME,
        variable: ['data', 'token'],
    },
    CALL_NOT_FOUND: {
        ...COMMON_VOIP_ERRORS.CALL_NOT_FOUND,
        mutation: SERVICE_NAME,
        variable: ['data', 'callId'],
    },
    INVALID_CONFIG: {
        mutation: SERVICE_NAME,
        code: INTERNAL_ERROR,
        type: 'INVALID_CONFIG',
        message: 'Config is not configured properly',
    },
    INVALID_DTMF_CODE: {
        mutation: SERVICE_NAME,
        code: BAD_USER_INPUT,
        type: 'INVALID_DTMF_CODE',
        message: 'DTMF code is empty',
        variable: ['data', 'data', 'dtmfCode'],
    },
    INVALID_ACCESS_TOKEN: {
        mutation: SERVICE_NAME,
        code: INTERNAL_ERROR,
        type: 'INVALID_ACCESS_TOKEN',
        message: 'Access token for intercoms is invalid',
    },
    UNKNOWN_ERROR: {
        mutation: SERVICE_NAME,
        code: INTERNAL_ERROR,
        type: 'UNKNOWN_ERROR',
        message: 'Unknown error',
    },
    APP_NOT_ALLOWED: {
        mutation: SERVICE_NAME,
        code: FORBIDDEN,
        type: 'APP_NOT_ALLOWED',
        message: 'You are not allowed to send dtmf for this app',
    },
}

async function checkLimitsByCall (context, { addressKey, app, callId }) {
    const searchKey = `${app.id}-${addressKey}-${callId}`

    await redisGuard.checkCustomLimitCounters(
        `${SERVICE_NAME}-${searchKey}`,
        SEND_DTMF_TO_B2C_APP_LIMIT_BY_CALL_WINDOW_DURATION_IN_SECONDS,
        SEND_DTMF_TO_B2C_APP_LIMIT_BY_CALL_MAX_REQUESTS_PER_WINDOW,
        context,
    )
}

async function checkLimitsByIp (context) {
    const ip = context.req.ip
    const userId = context.authedItem?.id

    const searchKey = `${ip}-${userId}`

    await redisGuard.checkCustomLimitCounters(
        `${SERVICE_NAME}-${searchKey}`,
        SEND_DTMF_TO_B2C_APP_LIMIT_BY_USER_WINDOW_DURATION_IN_SECONDS,
        SEND_DTMF_TO_B2C_APP_LIMIT_BY_USER_MAX_REQUESTS_PER_WINDOW,
        context,
    )
}

async function sendDTMFCode ({ context, url, callId, dtmfCode, accessToken }) {
    if (!dtmfCode) {
        throw new GQLError(ERRORS.INVALID_DTMF_CODE, context)
    }

    if (!url.trim()) {
        throw new GQLError(ERRORS.INVALID_CONFIG, context)
    }

    let error = null
    let response = null
    let responseJSON = null

    try {
        response = await fetch(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                ...(accessToken ? { Authorization: `Bearer ${accessToken}` } : {}),
            },
            body: JSON.stringify({
                callId, dtmfCode,
            }),
        })

        responseJSON = await response.json()
    } catch (err) {
        logger.error({ msg: 'sendDTMFCode result', err })
        throw new GQLError(ERRORS.UNKNOWN_ERROR, context)
    }

    if (!response) {
        throw new GQLError(ERRORS.UNKNOWN_ERROR, context)
    }

    if (response.status < 200 || response.status > 299) {
        error = ERRORS.UNKNOWN_ERROR
        
        if (response.status === 403) {
            error = ERRORS.INVALID_ACCESS_TOKEN
        }
        
        if (response.status === 404) {
            error = ERRORS.CALL_NOT_FOUND
        }

        throw new GQLError(error, context)
    }

    logger.info({ msg: 'sendDTMFCode result', data: { responseJSON, status: response?.status } })
}

const SendDTMFToB2CAppService = new GQLCustomSchema('SendDTMFToB2CAppService', {
    types: [
        {
            access: true,
            type: `input SendDTMFToB2CAppData {
            """
            Code for opening intercom, same which was sent in voip call
            """
            dtmfCode: String!
            }`,
        },
        {
            access: true,
            type: `input SendDTMFToB2CAppInput {
                    dv: Int!,
                    sender: SenderFieldInput!,
                    """
                    Token with data about the call. Received in voip push messages.
                    """
                    token: String!,
                    data: SendDTMFToB2CAppData!
                }`,
        },
        {
            access: true,
            type: `type SendDTMFToB2CAppOutput { 
                  """
                  "OK" string, otherwise an error will be thrown
                  """
                  status: String! 
                }`,
        },
    ],
    
    mutations: [
        {
            access: access.canSendDTMFToB2CApp,
            schema: 'sendDTMFToB2CApp(data: SendDTMFToB2CAppInput!): SendDTMFToB2CAppOutput',
            resolver: async (parent, args, context) => {
                const { data: argsData } = args
                const { token, data: { dtmfCode } } = argsData

                checkDvAndSender(argsData, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)

                await checkLimitsByIp(context)

                const tokenData = parseCallStatusJWTToken(token)
                if (!tokenData) {
                    throw new GQLError(ERRORS.CALL_NOT_FOUND, context)
                }

                if (!isCallIdValid(tokenData.callId)) {
                    throw new GQLError(ERRORS.INVALID_CALL_ID, context)
                }

                await checkLimitsByCall(context, { ...tokenData, app: { id: tokenData.b2cAppId } })

                const callStatus = await getCallStatus(tokenData)
                if (!callStatus || callStatus.status === CALL_STATUS_ENDED) {
                    throw new GQLError(ERRORS.CALL_NOT_FOUND, context)
                }
                if (!isCallStatusTokenEqual({ callStatus, callStatusToken: tokenData.callStatusToken })) {
                    throw new GQLError(ERRORS.CALL_NOT_FOUND, context)
                }

                const b2cApp = await B2CApp.getOne(context, {
                    id: tokenData.b2cAppId,
                    intercomConfig: {
                        sendDTMFUrl_not: null,
                        deletedAt: null,
                    },
                    deletedAt: null,
                }, 'id intercomConfig { sendDTMFUrl accessToken }')
                if (!b2cApp) {
                    throw new GQLError(ERRORS.APP_NOT_ALLOWED, context)
                }

                let accessToken = null
                if (b2cApp.intercomConfig.accessToken) {
                    accessToken = encryptionManager.decrypt(b2cApp.intercomConfig.accessToken)
                }

                await sendDTMFCode({
                    context,
                    url: b2cApp.intercomConfig.sendDTMFUrl, 
                    accessToken: accessToken, 
                    dtmfCode, callId: tokenData.callId,
                })

                return {
                    status: 'OK',
                }
            },
        },
    ],
    
})

module.exports = {
    SendDTMFToB2CAppService,
    ERRORS,
}
